import { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { CreateGroupDTO, ConnectTelegramDTO } from './group.dto';
import { groupCreateValidator, linkTelegramValidator } from './group.validator';
import { logger } from '../../middlewares/logger';

export class GroupController {
  private groupService: GroupService;

  constructor() {
    this.groupService = new GroupService();
  }

  public async createGroup(req: Request, res: Response, next: NextFunction): Promise<void> {
    const { error } = groupCreateValidator(req.body);
    if (error) {
      return next(error);
    }

    try {
      const group = await this.groupService.createGroup(new CreateGroupDTO(req.body));
      res.json({ success: true, data: group, meta: { requestId: req.id, timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (err) {
      next(err);
    }
  }

  public async linkTelegram(req: Request, res: Response, next: NextFunction): Promise<void> {
    const { error } = linkTelegramValidator(req.body);
    if (error) {
      return next(error);
    }

    try {
      const result = await this.groupService.linkTelegram(req.params.id, new ConnectTelegramDTO(req.body));
      res.json({ success: true, data: result, meta: { requestId: req.id, timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (err) {
      next(err);
    }
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDTO, ConnectTelegramDTO } from './group.dto';
import { AppError } from '../../middlewares/error.handler';

export class GroupService {
  private groupRepository: GroupRepository;

  constructor() {
    this.groupRepository = new GroupRepository();
  }

  public async createGroup(createGroupDTO: CreateGroupDTO): Promise<any> {
    try {
      return await this.groupRepository.create(createGroupDTO);
    } catch (err) {
      throw new AppError('Group creation failed', 'GROUP_CREATION_ERROR');
    }
  }

  public async linkTelegram(groupId: string, connectTelegramDTO: ConnectTelegramDTO): Promise<any> {
    try {
      return await this.groupRepository.updateTelegramLink(groupId, connectTelegramDTO);
    } catch (err) {
      throw new AppError('Linking Telegram failed', 'TELEGRAM_LINK_ERROR');
    }
  }
}

import { GroupModel } from '../../models/group.model';
import { CreateGroupDTO, ConnectTelegramDTO } from './group.dto';

export class GroupRepository {
  public async create(createGroupDTO: CreateGroupDTO): Promise<any> {
    return new GroupModel(createGroupDTO).save();
  }

  public async updateTelegramLink(groupId: string, connectTelegramDTO: ConnectTelegramDTO): Promise<any> {
    return GroupModel.findByIdAndUpdate(groupId, { telegramChatId: connectTelegramDTO.telegramChatId }, { new: true });
  }
}

export class CreateGroupDTO {
  public name: string;
  public description: string;
  public adminId: string;

  constructor(data: any) {
    this.name = data.name;
    this.description = data.description;
    this.adminId = data.adminId;
  }
}

export class ConnectTelegramDTO {
  public telegramChatId: string;

  constructor(data: any) {
    this.telegramChatId = data.telegramChatId;
  }
}

import * as z from 'zod';

export const groupCreateSchema = z.object({
  name: z.string().min(1),
  description: z.string().max(255),
  adminId: z.string().uuid()
});

export const linkTelegramSchema = z.object({
  telegramChatId: z.string().min(1)
});

export const groupCreateValidator = (data: any) => groupCreateSchema.safeParse(data);
export const linkTelegramValidator = (data: any) => linkTelegramSchema.safeParse(data);

import { Schema, model } from 'mongoose';

const GroupSchema = new Schema({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Schema.Types.ObjectId, required: true, ref: 'User' },
  members: [{ type: Schema.Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export const GroupModel = model('Group', GroupSchema);

import pino from 'pino';

export const logger = pino({
  transport: {
    target: 'pino-pretty',
    options: {
      colorize: true
    }
  },
  base: {
    pid: false
  },
  timestamp: () => `,"time":"${new Date().toISOString()}"`
});
